public struct TagMessage {
    public var from: String
    public var target: String
    public var tags: [TagEntry]

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(from: String, target: String, tags: [TagEntry]) {
        self.from = from
        self.target = target
        self.tags = tags
    }
}

#if compiler(>=6)
extension TagMessage: Sendable {}
#endif


extension TagMessage: Equatable, Hashable {
    public static func ==(lhs: TagMessage, rhs: TagMessage) -> Bool {
        if lhs.from != rhs.from {
            return false
        }
        if lhs.target != rhs.target {
            return false
        }
        if lhs.tags != rhs.tags {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(from)
        hasher.combine(target)
        hasher.combine(tags)
    }
}

